def validate(args, output):
    groupSizes = args[0]
    n = len(groupSizes)
    if not isinstance(output, list):
        return False
    # every person appears exactly once
    seen = []
    for grp in output:
        if not isinstance(grp, list):
            return False
        seen.extend(grp)
    if sorted(seen) != list(range(n)):
        return False
    # each group has the correct size and all members agree on that size
    for grp in output:
        sz = len(grp)
        for idx in grp:
            if not (0 <= idx < n):
                return False
            if groupSizes[idx] != sz:
                return False
    return True

