function validate(args, output) {
    const groupSizes = args[0];
    const n = groupSizes.length;
    if (!Array.isArray(output)) return false;
    const seen = [];
    for (const grp of output) {
        if (!Array.isArray(grp)) return false;
        for (const idx of grp) seen.push(idx);
    }
    if (seen.length !== n) return false;
    seen.sort((a, b) => a - b);
    for (let i = 0; i < n; i++) if (seen[i] !== i) return false;
    for (const grp of output) {
        const sz = grp.length;
        for (const idx of grp) {
            if (idx < 0 || idx >= n) return false;
            if (groupSizes[idx] !== sz) return false;
        }
    }
    return true;
}

