class Solution:
    def groupThePeople(self, groupSizes):
        from collections import defaultdict
        buckets = defaultdict(list)
        for i, s in enumerate(groupSizes):
            buckets[s].append(i)
        result = []
        for s, indices in buckets.items():
            for start in range(0, len(indices), s):
                result.append(sorted(indices[start:start + s]))
        result.sort()
        return result

